function validate(args, output) {
    const orig = args[0];
    const origVals = orig.filter(v => v !== null).slice().sort((a, b) => a - b);
    function deser(a) {
        if (!a || a.length === 0) return null;
        const root = [a[0], null, null];
        const q = [root]; let i = 1;
        while (q.length && i < a.length) {
            const node = q.shift();
            if (i < a.length) { if (a[i] !== null) { node[1] = [a[i], null, null]; q.push(node[1]); } i++; }
            if (i < a.length) { if (a[i] !== null) { node[2] = [a[i], null, null]; q.push(node[2]); } i++; }
        }
        return root;
    }
    const root = deser(output);
    const ino = [];
    const st = []; let node = root;
    while (st.length || node) {
        while (node) { st.push(node); node = node[1]; }
        node = st.pop(); ino.push(node[0]); node = node[2];
    }
    if (ino.length !== origVals.length) return false;
    for (let k = 0; k < ino.length; k++) if (ino[k] !== origVals[k]) return false;
    let balanced = true;
    function height(n) {
        if (n === null) return 0;
        const hl = height(n[1]);
        const hr = height(n[2]);
        if (Math.abs(hl - hr) > 1) balanced = false;
        return Math.max(hl, hr) + 1;
    }
    height(root);
    return balanced;
}

