class Solution:
    def balanceBST(self, root):
        vals = []
        def inorder(n):
            if not n:
                return
            inorder(n.left)
            vals.append(n.val)
            inorder(n.right)
        inorder(root)
        def build(lo, hi):
            if lo > hi:
                return None
            mid = (lo + hi) // 2
            node = TreeNode(vals[mid])
            node.left = build(lo, mid - 1)
            node.right = build(mid + 1, hi)
            return node
        return build(0, len(vals) - 1)

